def search_offline_stations(query):
    """
    Search local dict for stations matching code or name (case-insensitive).
    """
    q = query.lower().strip()
    results = []
    
    # Exact match code first
    for s in STATIONS:
        if s["code"].lower() == q:
            results.insert(0, s)
            
    # Fuzzy match names
    for s in STATIONS:
        if q in s["name"].lower() and s not in results:
            results.append(s)
            
    return results[:15]  # Return top 15 matches
